BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqType ?name ?pkgName WHERE {
  VALUES ?pkg { 
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::02%20Requirements%20Flow-down%20Views>
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::03%20APS%20Requirements%20individual%20views>
  }
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?pkgName . }

  ?pkg vocab:packagedElement+ ?req .
  ?req rdf:type ?reqType .

  FILTER(
    ?reqType = vocab:tmt%20requirement ||
    CONTAINS(STR(?reqType), "requirement")
  )
  OPTIONAL { ?req vocab:NamedElement_name ?name . }
}
ORDER BY ?pkgName ?name
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  VALUES ?pkg { 
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::02%20Requirements%20Flow-down%20Views>
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::03%20APS%20Requirements%20individual%20views>
  }
  ?pkg (vocab:packagedElement+|vocab:Element_ownedElement+|vocab:ownedElement+|vocab:Element_ownedElement*) ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqType ?name ?pkgName WHERE {
  VALUES ?pkg { 
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::02%20Requirements%20Flow-down%20Views>
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::03%20APS%20Requirements%20individual%20views>
  }
  ?req rdf:type ?reqType .
  FILTER(CONTAINS(STR(?reqType), "requirement"))
  OPTIONAL { ?req vocab:NamedElement_name ?name . }

  OPTIONAL { 
    ?req vocab:Element_owner ?directOwner .
    ?directOwner (vocab:Element_owner*) ?pkg .
  }
  BIND(STRAFTER(STR(?pkg), "http://api.koneksys.com/cameo/") AS ?pkgName)
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?reqKey ?reqName ?inWhere (COUNT(DISTINCT ?pkg) AS ?pkgCount) WHERE {
  {
    VALUES ?pkg { 
      <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::02%20Requirements%20Flow-down%20Views>
      <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Black%20Box%20Specification::Requirements::03%20APS%20Requirements%20individual%20views>
    }

    ?req rdf:type vocab:tmt%20requirement .

    # key: prefer MDObject_ID if present, else fall back to name
    OPTIONAL { ?req vocab:MDObject_ID ?reqKeyRaw . }
    OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
    BIND(COALESCE(?reqKeyRaw, ?reqName, STR(?req)) AS ?reqKey)

    # determine where the requirement is owned from (direct owner chain)
    ?req vocab:Element_owner+ ?pkg .

    BIND(
      IF(CONTAINS(LCASE(STR(?pkg)), "flow-down%20views") || CONTAINS(LCASE(STR(?pkg)), "flow%20down%20views"), "flow-down views", "individual views")
      AS ?inWhere
    )
  }
}
GROUP BY ?reqKey ?reqName ?inWhere
HAVING (?pkgCount > 1)
ORDER BY DESC(?pkgCount)
LIMIT 25
